const event = $json.body && $json.body.events && $json.body.events.length > 0 ?   
  $json.body.events[0] :  
  null;

console.log("=== Parse Postback Data ===");

if (!event) {
  console.log("??No event found");
  return [{
    json: {
      userId: "unknown",
      replyToken: "unknown",
      messageType: 'unknown',
      mode: 'welcome',
      action: null,
      hasError: true
    }
  }];
}

const userId = event.source?.userId || "unknown";
const replyToken = event.replyToken;

console.log("??Parsed Event:", { userId, replyToken, eventType: event.type });

// ===== 6??蝟餃??扯” (摰靽?) =====
const cuisineMap = {
  'chinese': '銝剖???',
  'taiwanese': '銝剖???',
  'bbq': '銝剖???',
  'seafood': '銝剖???',
  'japanese': '?亙???',
  'hotpot': '?恍?',
  'healthy': '?亙熒擗?,
  'vegetarian': '?亙熒擗?,
  'cafe': '?撱?,
  'international': '?啣???',
  'italian': '?啣???',
  'korean': '?啣???'
};

const cuisineMapReverse = {
  '銝剖???': 'chinese',
  '?亙???': 'japanese',
  '?恍?': 'hotpot',
  '?亙熒擗?: 'healthy',
  '?撱?: 'cafe',
  '?啣???': 'international'
};

const chineseCuisines = Object.values(cuisineMap);

// ===== Follow 鈭辣 (摰靽?) =====
if (event.type === 'follow') {
  console.log("Event type: follow");
  return [{
    json: {
      userId: userId,
      replyToken: replyToken,
      messageType: 'follow',
      action: 'follow',
      mode: 'welcome',
      originalText: 'follow'
    }
  }];
}

// ===== Text Message (摰靽?嚗?隤踵???Action) =====
if (event.message && event.message.type === 'text') {
  const text = (event.message.text || "").trim();
  const textLower = text.toLowerCase();

  console.log("Event type: text message, Text:", text);

  if (text === "??啁??!") {
    console.log("??Action: first_time");
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageText: text,
        messageType: 'text',
        action: "first_time",
        mode: "setup_profile",
        originalText: text
      }
    }];
  }

  if (text === "??野鈭?!") {
    console.log("??Action: existing_user");
    // ???ㄐ靽格?箄孛?潛Ⅱ隤?蝵格芋撘??園?甈?靽?
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageText: text,
        messageType: 'text',
        action: "existing_user",
        mode: "confirm_location", 
        originalText: text
      }
    }];
  }

  if (textLower.includes("trip") && textLower.includes("閬?")) {
    console.log("??Mode: trip_planning");
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageText: text,
        messageType: 'text',
        action: "trip_planning",
        mode: "trip_planning",
        originalText: text
      }
    }];
  }

  if (textLower.includes("instant") && textLower.includes("??")) {
    console.log("??Mode: instant_search");
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageText: text,
        messageType: 'text',
        action: "instant_search",
        mode: "instant_search",
        originalText: text
      }
    }];
  }

  if (textLower.includes("query") || textLower.includes("history") || textLower.includes("甇瑕")) {
    console.log("??Mode: query_history");
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageText: text,
        messageType: 'text',
        action: "query_history",
        mode: "query_history",
        originalText: text
      }
    }];
  }

  if (chineseCuisines.includes(text)) {
    const cuisineEnglish = cuisineMapReverse[text] || '';
    console.log("??Cuisine selected (text input):", text);
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageText: text,
        messageType: 'text',
        action: "select_cuisine",
        mode: "select_cuisine",
        cuisine_type: text,
        cuisine_type_english: cuisineEnglish,
        originalText: text
      }
    }];
  }

  // ?桅?摮??航?舀迤?冽?啣???嚗n  console.log("Mode: unknown (normal text message)");
  return [{
    json: {
      userId: userId,
      replyToken: replyToken,
      messageText: text,
      messageType: 'text',
      action: "text_input", // ??憓?霅?嫣噶敺??斗?湔?啣?
      mode: 'unknown',
      originalText: text
    }
  }];
}

// ===== Postback (摰靽?銝行??交?摩) =====
if (event.postback && event.postback.data) {
  const postbackData = event.postback.data;
  console.log("Event type: postback", postbackData);

  const params = {};
  const pairs = postbackData.split('&');
  for (let i = 0; i < pairs.length; i++) {
    const pair = pairs[i].split('=');
    if (pair.length === 2) {
      params[decodeURIComponent(pair[0])] = decodeURIComponent(pair[1]);
    }
  }

  const action = params.action || 'unknown';
  console.log("??Postback Parsed:", { action, params });

  // --- ?? ?啣?嚗?嗡?蝵桃Ⅱ隤???(銝蔣?踹?蝥? ---
  if (action === 'use_stored_location') {
    return [{ json: { userId, replyToken, messageType: 'postback', action, mode: 'existing_mode_selection', originalText: postbackData } }];
  }
  if (action === 'update_location_trigger') {
    return [{ json: { userId, replyToken, messageType: 'postback', action, mode: 'asking_new_address', originalText: postbackData } }];
  }
  // --- ?? ?啣?嚗???閬賢???---
  if (action === 'show_cuisine_page1' || action === 'show_cuisine_page2') {
    return [{ json: { userId, replyToken, messageType: 'postback', action, mode: 'select_cuisine_navigation', originalText: postbackData } }];
  }

  // --- Setup ????(摰靽?) ---
  if (action === 'setup_profile') {
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageType: 'postback',
        action: 'setup_profile',
        mode: 'setup_profile',
        setup_step: 0,
        originalText: postbackData
      }
    }];
  }

  // --- Setup 甇仿??? (摰靽?) ---
  if (['setup_gender', 'setup_dietary', 'setup_allergies', 'setup_dislikes'].includes(action)) {
    const setupValue = params.value || '';
    const currentStep = parseInt(params.step) || 0;
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageType: 'postback',
        action: action,
        mode: 'setup_profile',
        setup_step: currentStep + 1,
        setup_value: setupValue,
        originalText: postbackData
      }
    }];
  }

  // --- Instant Search (摰靽?) ---
  if (action === 'instant_search' || action === 'instant_search_start') {
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageType: 'postback',
        action: action,
        mode: 'instant_search',
        search_type: params.search_type || 'quick',
        originalText: postbackData
      }
    }];
  }

  // --- Trip Planning (摰靽?) ---
  if (action === 'trip_planning' || action === 'trip_planning_start') {
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageType: 'postback',
        action: action,
        mode: 'trip_planning',
        originalText: postbackData
      }
    }];
  }

  // --- Query History (摰靽?) ---
  if (action === 'query_history') {
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageType: 'postback',
        action: action,
        mode: 'query_history',
        originalText: postbackData
      }
    }];
  }

  // --- ?頂?豢?嚗?誨蝣潘? (摰靽?????? ---
  if (action === 'cuisine') {
    const cuisineEnglish = params.cuisine || '';
    const cuisineChinese = cuisineMap[cuisineEnglish] || cuisineEnglish;
    console.log("??Cuisine (action=cuisine):", { cuisineEnglish, cuisineChinese });
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageType: 'postback',
        action: action,
        mode: 'select_cuisine',
        cuisine_type: cuisineChinese,
        cuisine_type_english: cuisineEnglish,
        search_type: params.search_type || 'quick',
        sort_by: params.sort_by || '',
        originalText: postbackData
      }
    }];
  }

  // --- ?頂?豢?嚗葉??蝔梧? (摰靽?) ---
  if (action === 'select_cuisine') {
    const cuisineChinese = params.cuisine || '';
    const cuisineEnglish = cuisineMapReverse[cuisineChinese] || '';
    console.log("??Cuisine (action=select_cuisine):", { cuisineChinese, cuisineEnglish });
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageType: 'postback',
        action: action,
        mode: 'select_cuisine',
        cuisine_type: cuisineChinese,
        cuisine_type_english: cuisineEnglish,
        originalText: postbackData
      }
    }];
  }

 // --- ?? ?刻?? (?芸????舀 UUID 蝎暹?餈質馱) ---
  if (action === 'like' || action === 'like_or_dislike') {
  console.log("??Feedback received:", { action, res_id: params.res_id });

    const cuisineEnglish = params.cuisine_type || '';
    const cuisineChinese = cuisineMap[cuisineEnglish] || cuisineEnglish;

    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageType: 'postback',
        action: 'like',               // 蝯曹?頛詨??like ?嫣噶敺? Switch
        mode: 'update_feedback',      // 璅?璅∪?
        recommendation_id: params.rec_id || '',      // 銝餉” ID (??
        restaurant_detail_id: params.res_id || params.restaurant_id || '', // ?詨捆?啗? ID
        restaurant_name: params.name || params.restaurant_name || '?振擗輒',
