// ?蕪銝行?摨?撱喉??詨瘛瑕??頂??Top6
// ?舀??頂嚗葉撘??撘???摨琿???????∪輒

const input = Array.isArray($json) ? $json[0] : $json;
const restaurants = input. output?. classified_restaurants || input.classified_restaurants || [];

console.log("=== Restaurant Filter & Rank ===");
console.log("Input restaurants count:", restaurants.length);

if (restaurants.length === 0) {
  return {
    userId: input.userId || $json.userId,
    replyToken: input.replyToken || $json.replyToken,
    mixed_top6: [],
    total_count: 0,
    classified_count: 0,
    hasError: true
  };
}

// 1. ????摨?(敺??唬?)
const sorted = restaurants.sort((a, b) => (b.rating || 0) - (a.rating || 0));

// 2. ?詨瘛瑕??頂??Top6 - ?舀?6??蝟蓋nconst cuisineTypes = ['銝剖???', '?亙???', '?恍?', '?亙熒擗?, '?啣???', '?撱?];
const selected = [];
const usedCuisines = new Set();

// ???頂?訾?摰嗡誨銵剁??擃???嚗nfor (const cuisine of cuisineTypes) {
  const best = sorted.find(r => 
    r.cuisine_type === cuisine && ! selected.includes(r)
  );
  if (best) {
    selected.push(best);
    usedCuisines.add(cuisine);
    console.log(`??Selected ${cuisine}:  ${best.name}`);
  }
}

// 鋆雲??6 摰跚nfor (const r of sorted) {
  if (selected.length >= 6) break;
  if (!selected.includes(r)) {
    selected.push(r);
  }
}

console.log(`??Final selection: ${selected.length} restaurants`);

return {
  userId: input.userId || $json.userId,
  replyToken: input.replyToken || $json.replyToken,
  mixed_top6: selected.slice(0, 6),
  total_count: sorted.length,
  classified_count: restaurants.length
};

